{"file_path":"/project/ktlint-ruleset-standard/src/test/kotlin/com/pinterest/ktlint/ruleset/standard/rules/FunctionSignatureRuleAnnotatedExpressionTest.kt","content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue
import com.pinterest.ktlint.ruleset.standard.rules.FunctionSignatureRule.Companion.FUNCTION_BODY_EXPRESSION_WRAPPING_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.EOL_CHAR
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.MAX_LINE_LENGTH_MARKER
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class FunctionSignatureRuleAnnotatedExpressionTest {
    private val functionSignatureRuleAssertThat = assertThatRule { FunctionSignatureRule() }

    @Test
    fun `Given an expression body that starts with an annotation then do not merge first line with function signature`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                                             $EOL_CHAR
            fun f(): String =
                @Suppress("DEPRECATION")
                "x"
            """.trimIndent()

        functionSignatureRuleAssertThat(code)
            .setMaxLineLength()
            .withEditorConfigOverride(
                CODE_STYLE_PROPERTY to CodeStyleValue.android_studio,
                FUNCTION_BODY_EXPRESSION_WRAPPING_PROPERTY to FunctionSignatureRule.FunctionBodyExpressionWrapping.default,
            ).hasNoLintViolations()
    }
}
"}

